<template>
  <div class="all">
    <div class="back">
      <router-link to="/home" style="font-size: large">
        <el-page-header title="BACK"></el-page-header>
      </router-link>
    </div>
    <div class="info">
      <span> Title: </span>
      <input class="input" v-model="title"
             placeholder="文章的标题" required/>
    </div>
    <br>
    <div class="info">
      <span>Author: </span>
      <input class="input" v-model="author" disabled/>
    </div>
    <br>
    <div class="info">
      <span>Abstract: </span>
      <input class="input" v-model="abstract"
             placeholder="文章的核心或者简介" required/>
    </div>
    <div class="btnGroups">
      <span> Function:</span>
      <button class="btn" @click="upload" title="将下面的文章上交审核">Upload</button>
      <button class="btn" title="保存已经编写的文章" disabled>Save</button>

      <label for="fileInput">
        <input type="button" class="btn" value="SELECT"><span class="inputMD">{{ mdFileName }}</span>
        <input type="file" @change="getFile($event)" class="fileUpload" accept=".md">
      </label>
    </div>

    <br>
    <div class="edit">
      <v-md-editor v-model="source" height="40em" mode="edit" :disabled-menus="[]"
                   @upload-image="handleUploadImage"></v-md-editor>
    </div>

  </div>
</template>
<script>
import axios from 'axios'
import {ElMessage} from 'element-plus'
import VMdEditor from "@kangc/v-md-editor/lib/codemirror-editor";
import ObsClient from "esdk-obs-browserjs";

export default {
  name: 'LunTan',
  components: {
    'v-md-editor': VMdEditor,
  },
  data() {
    return {
      source: '',
      title: '',
      author: '',
      abstract: '',
      passage: '',
      mdFileName: 'md-file',

    }
  },
  created() {
    if (localStorage.getItem('username') === null) {
      this.open("Please Login")
      this.$router.push({path: '/'})
    } else {
      this.author = localStorage.getItem('username')
    }
  },
  methods: {
    open(msg) {
      ElMessage({
        message: msg,
        type: 'success'
      })
    },
    upload() {
      let passage = {
        title: this.title,
        author: this.author,
        abstract: this.abstract,
        date: this.getCurrentTime(),
        passage: this.source,
      }
      if (passage.title === '' || passage.author === '' || passage.abstract === '' || passage.passage === '') {
        alert("check empty!!")
        return
      }
      axios({
        method: "post",
        url: "https://46631031u1.hsk.top/editblog",
        data: passage,
      }).then((res) => {
        console.log(res.data)
        if (res.data.message === 'successfully') {
          this.open('store successfully..')
        } else {
          this.open(res.data)
        }
      }).catch((err) => {
        console.log(err)
        this.open(err)
      })
    },
    handleUploadImage(event, insertImage, files) {
      // Huawei OBS 储存
      let obsClient = new ObsClient({
        access_key_id: 'CUYMJEJSUMJKBPIQEXXI', // ak
        secret_access_key: 'uryAfDBGvONgA8JlMDvxTnSEx4TqTdCFKLodl9Fe', // sk
        server: 'obs.cn-east-2.myhuaweicloud.com'
      })
      obsClient.putObject({
        Bucket: 'lky-img', // 桶名
        Key: this.author + files[0].name, // 路径 + 文件名
        SourceFile: files[0],
      })
      insertImage({
        url: "https://lky-img.obs.cn-east-2.myhuaweicloud.com/" + this.author + files[0].name,
        desc: files[0].name,
      });
    },
    getFile(event) {
      let file = event.target.files[0];
      let imgName = file.name;
      let idx = imgName.lastIndexOf(".");
      if (idx !== -1) {
        let ext = imgName.substr(idx + 1).toUpperCase();
        ext = ext.toLowerCase();
        if (ext !== 'md') {
          this.open("并不是md文件")
        } else {
          // this.MdFile = file
          // console.log(this.MdFile.file)
          //
          let reader = new FileReader()
          // reader.onloadstart = function () {
          //   console.log("开始加载..");
          // };
          //
          // reader.onprogress = function () {
          //   console.log("正在加载(Bytes：" + file.size + ")..");
          // };
          const _this = this
          // reader.onload = function () {
          //   console.log("完成加载..");
          // };

          reader.onloadend = function () {
            if (reader.error) {
              console.log("读取失败")
            } else {
              _this.$nextTick(() => {
                _this.source = reader.result
              })
            }
          }
          reader.readAsText(file)
          this.mdFileName = file.name
        }
      } else {
        this.open("不是md文件")
      }

    },
    getCurrentTime() {
      let nowDate = new Date()
      let date = {
        year: nowDate.getFullYear(),
        month: nowDate.getMonth(),
        day: nowDate.getDay(),
        hour: nowDate.getHours(),
        minutes: nowDate.getMinutes(),
        second: nowDate.getSeconds(),
      }
      return date.year + '-' + date.month + '-' + date.day + ' ' + date.hour + ':' + date.minutes + ':' + date.second
    }
  },
}
</script>

<style scoped>
a {
  font-size: 1.5em;
  font-family: "Lucida Console", "Courier New", monospace;
  margin: 1em 0;
  position: absolute;
  left: 0.5%;
  top: 0;
}

.all {
  display: flex;
  flex-direction: column;
  font-size: 1em;
  font-family: "Lucida Console", "Courier New", monospace;
  background-color: #e0cdf5;
}

.back {
  margin-bottom: 4em;
}

.info {
  display: flex;
  flex-direction: row;
  width: 37em;
  height: 1.8em;
  align-items: center;
}

.info span {
  width: 18.92%;
}

.input {
  width: 81.08%;
  height: 100%;
  color: #f30d20;
  font-size: 1em;
  font-family: "Lucida Console", "Courier New", monospace;
  letter-spacing: 0.05em;
  text-indent: 0.5em;
}

.edit {
  display: flex;
  flex-direction: column;
  align-items: center;
}

.btnGroups {
  margin-top: 1em;
  font-family: "Lucida Console", "Courier New", monospace;
  display: flex;
  flex-direction: row;
  align-items: center;
}

label {
  position: relative;
}

.fileUpload {
  position: absolute;
  left: 0;
  top: 0;
  opacity: 0;
}

.btn {
  font-family: "Lucida Console", "Courier New", monospace;
  font-size: 1em;
  color: #524562;
  width: 5em;
  height: 1.8em;
  border: 2px solid #1b1621;
  border-radius: 3%;
  margin-right: 0.5em;
  margin-left: 2.5em;
}

.inputMD {
  font-size: 1em;
  opacity: 0.6;
}

@media (max-width: 700px) {
  .info {
    width: auto;
  }

  .btn {
    font-size: small;
    width: 5em;
    margin-right: 0.5em;
    margin-left: 2.2em;
  }
}
</style>