<template>
  <div class="body">
    <div class="stars" ref="starsRef">
      <div class="star" v-for="(item, index) in starsCount" :key="index"></div>
    </div>
    <div class="login_box" v-if="loginVision">
      <!-- 登录表单区域 -->
      <el-form size="medium">
        <img class="img" src="../assets/font.png" alt="logo">
        <!-- 用户名 -->
        <el-form-item class="item-1">
          <input placeholder="UserName" v-model="username" class="input">
        </el-form-item>
        <!-- 密码 -->
        <el-form-item class="item-1">
          <input type="password" placeholder="PassWord" v-model="password" class="input">
        </el-form-item>

        <!-- 登录按钮 -->
        <el-form-item class="item-1">
          <el-button type="primary" class="btn" @click="login">登录</el-button>
        </el-form-item>

        <el-form-item class="item-1">
          <el-button type="primary" class="btn" @click="this.loginVision=false;this.dialogVision=true"
                     color="blueviolet">注册
          </el-button>
        </el-form-item>
      </el-form>
    </div>
    <div class="dialog" v-if="dialogVision">
      <el-form>
        <!-- 用户名 -->
        <el-form-item class="item">
          <input placeholder="UserName" v-model="username" class="input">
        </el-form-item>
        <!-- 密码 -->
        <el-form-item class="item">
          <input type="password" placeholder="PassWord" v-model="password" class="input">
        </el-form-item>
        <!-- 确认密码-->
        <el-form-item class="item">
          <input type="password" placeholder="RE-PassWord" v-model="password" class="input">
        </el-form-item>

        <!-- 注册按钮 -->
        <el-form-item class="item">
          <el-button type="primary" class="btn" @click="register">注册</el-button>
        </el-form-item>
      </el-form>
    </div>
  </div>
</template>

<script>
import {ElMessage} from "element-plus"
import {ref} from 'vue'
import axios from 'axios'

export default {
  data() {
    return {
      starsCount: 2000, //星星数量
      distance: 500, //间距
      username: '',
      password: '',
      loginVision: ref(true),
      dialogVision: ref(false),
    }
  },
  mounted() {
    console.log(this.$refs.starsRef.children);
    let starNodes = Array.from(this.$refs.starsRef.children);
    starNodes.forEach((item) => {
      let speed = 0.2 + Math.random();
      let thisDistance = this.distance + Math.random() * 300;
      item.style.transformOrigin = `0 0 ${thisDistance}px`;
      item.style.transform =
          `
		        translate3d(0,0,-${thisDistance}px)
		        rotateY(${Math.random() * 360}deg)
		        rotateX(${Math.random() * -50}deg)
		        scale(${speed},${speed})`;
    });
  },
  methods: {
    open(msg, type) {
      ElMessage({
        message: msg,
        type: type,
      })
    },
    login() {
      if (this.username === '' || this.password === '') {
        this.open('please check empty!!', 'warning')
        return
      }
      //管理员账户密码 不需要验证
      if (this.username === 'lky' && this.password === 'yyy') {
        this.open('Welcome administrator', 'success')
        localStorage.setItem('username', this.username)
        this.$router.push({path: '/home'})
        return
      }
      let data = {
        username: this.username,
        password: this.password,
      }
      axios({
        method: "post",
        url: "http://localhost:8081/login",
        data: data,
      }).then(res => {
        if (res.data.message === "Successfully") {
          this.open("Login Successfully", "success")
          localStorage.setItem('username', this.username)
          this.$router.push({path: '/home'})
        } else {
          this.open(res.data.message, "error")
        }
      }).catch(err => {
        console.log(err)
        this.open(err, "error")
      })
    },
    register() {
      this.loginVision = true
      this.dialogVision = false
    }
  }
}
</script>

